import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { authService } from '../../services/authService';
import './Header.css';

const Header = ({ user, onLogout }) => {
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const navigate = useNavigate();

  const handleLogout = () => {
    authService.removeToken();
    onLogout();
    navigate('/');
  };

  return (
    <header className="header">
      <div className="header__container">
        <div className="header__logo">
          <Link to="/">
            <img src="/assets/images/logo.png" alt="Tour Management" />
            <span>TourHub</span>
          </Link>
        </div>

        <nav className={`header__nav ${mobileMenuOpen ? 'header__nav--mobile' : ''}`}>
          <ul className="header__nav-list">
            <li className="header__nav-item">
              <Link to="/" className="header__nav-link">Home</Link>
            </li>
            <li className="header__nav-item">
              <Link to="/tours" className="header__nav-link">Tours</Link>
            </li>
            <li className="header__nav-item">
              <Link to="/about" className="header__nav-link">About</Link>
            </li>
            <li className="header__nav-item">
              <Link to="/gallery" className="header__nav-link">Gallery</Link>
            </li>
          </ul>
        </nav>

        <div className="header__actions">
          {user ? (
            <div className="header__user-menu">
              <span className="header__username">Welcome, {user.username}</span>
              <button onClick={handleLogout} className="header__btn header__btn--logout">
                Logout
              </button>
            </div>
          ) : (
            <div className="header__auth-buttons">
              <Link to="/login" className="header__btn header__btn--login">
                Login
              </Link>
              <Link to="/register" className="header__btn header__btn--register">
                Register
              </Link>
            </div>
          )}
        </div>

        <button 
          className="header__mobile-menu-btn"
          onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
        >
          <span></span>
          <span></span>
          <span></span>
        </button>
      </div>
    </header>
  );
};

export default Header;
